# Slash command aliases for the ticket workflow.
# Format: {alias} {target} — one pair per line, whitespace-separated.
# Lines starting with # and blank lines are ignored.
#
# install.sh reads this file and creates a symlink in commands/ for each alias
# pointing at the canonical command file (e.g. tl.md → ticket-list.md). The
# alias files themselves are gitignored so they exist on each machine without
# polluting the repo.
#
# To add a new alias: add a line here, commit, push, pull on other machines,
# re-run bash install.sh.

tn  ticket-new
tl  ticket-list
ts  ticket-status
ti  ticket-investigate
ta  ticket-approve
tr  ticket-review
tp  ticket-preview
tb  ticket-batch
tsh ticket-ship
td  ticket-defer
tc  ticket-close
tro ticket-reopen
tcl ticket-cleanup
